import React, { createContext, useContext, useState } from "react";

const CartContext = createContext();

export function CartProvider({ children }) {
  const [cartItems, setCartItems] = useState([]);
  const [lastOrder, setLastOrder] = useState(null); // ✅ NEW

  const addToCart = (medicine) => {
    setCartItems((prev) => {
      const exists = prev.find((i) => i.id === medicine.id);

      if (exists) {
        return prev.map((i) =>
          i.id === medicine.id && i.quantity < 5
            ? { ...i, quantity: i.quantity + 1 }
            : i
        );
      }

      return [...prev, { ...medicine, quantity: 1 }];
    });
  };

  const increaseQty = (id) => {
    setCartItems((prev) =>
      prev.map((i) =>
        i.id === id && i.quantity < 5
          ? { ...i, quantity: i.quantity + 1 }
          : i
      )
    );
  };

  const decreaseQty = (id) => {
    setCartItems((prev) =>
      prev
        .map((i) =>
          i.id === id ? { ...i, quantity: i.quantity - 1 } : i
        )
        .filter((i) => i.quantity > 0)
    );
  };

  // 🚀 CHECKOUT FUNCTION (NEW)
  const placeOrder = () => {
    if (cartItems.length === 0) return;

    const order = {
      items: cartItems,
      totalItems: cartItems.reduce((s, i) => s + i.quantity, 0),
      time: new Date().toLocaleString()
    };

    setLastOrder(order);   // store order
    setCartItems([]);      // clear cart AFTER saving
  };

  return (
    <CartContext.Provider
      value={{
        cartItems,
        addToCart,
        increaseQty,
        decreaseQty,
        placeOrder,
        lastOrder
      }}
    >
      {children}
    </CartContext.Provider>
  );
}

export function useCart() {
  return useContext(CartContext);
}
